// 解析 SimplyBook webhook payload
// 提取 booking_id, client info, service info, provider info, line_user_id
const payload = $json;

const booking_id = payload.booking_id || payload.id || '';
const event_type = payload.notification_type || 'new_booking';

// Client info
const client_name = (payload.client_name || payload.client_first_name || '') + ' ' + (payload.client_last_name || '');
const client_email = payload.client_email || '';
const client_phone = payload.client_phone || '';

// Service / Provider
const service_id = payload.event_id || payload.service_id || '';
const service_name = payload.event_name || payload.service_name || '';
const provider_id = payload.unit_id || payload.provider_id || '';
const provider_name = payload.unit_name || payload.provider_name || '';

// Booking datetime
const booking_datetime = payload.start_date_time || payload.start_date || '';

// Custom field: line_user_id（SimplyBook intake form 自訂欄位）
const custom_fields = payload.additional_fields || payload.custom_fields || {};
const line_user_id = custom_fields.line_user_id || '';

// Price
const price = payload.price || 0;

return [{
  json: {
    booking_id,
    event_type,
    client_name: client_name.trim(),
    client_email,
    client_phone,
    service_id,
    service_name,
    provider_id,
    provider_name,
    booking_datetime,
    line_user_id,
    price,
    raw_payload: JSON.stringify(payload)
  }
}];

// 記錄錯誤訊息
const error = {
  workflow: 'SimplyBook_Webhook__Booking_Sync',
  timestamp: new Date().toISOString(),
  input: $json,
  message: 'Creator API call failed or returned error'
};

console.error(JSON.stringify(error));

return [{ json: error }];
